import { QRCodeData } from '../types';

/**
 * Weekly QR String Generator
 * In a real production environment, this would be an Edge Function.
 * Here we simulate the logic for the frontend.
 */

const SALT = "AKTIVATE_BURUNDI_2024";

export const generateWeeklyQR = (expiryDate: Date): string => {
  const payload = {
    salt: SALT,
    validUntil: expiryDate.toISOString(),
    week: Math.floor(Date.now() / (7 * 24 * 60 * 60 * 1000))
  };
  return btoa(JSON.stringify(payload));
};

export const validateQRCode = (qrString: string, activeQR: QRCodeData): boolean => {
  try {
    const decoded = JSON.parse(atob(qrString));

    // Check if salt matches
    if (decoded.salt !== SALT) return false;

    // Check if matches the currently active DB record
    if (qrString !== activeQR.qr_data) return false;

    // Check expiration
    const expiry = new Date(decoded.validUntil);
    if (expiry < new Date()) return false;

    return true;
  } catch (e) {
    return false;
  }
};

import { useState, useCallback } from 'react';
import { OFFICE_COORDS, LATE_THRESHOLD_TIME, MAX_DISTANCE_METERS } from '../constants';
import { AttendanceRecord, CheckMethod } from '../types';

// Helper to calculate distance in meters (Haversine)
const getDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
  const R = 6371e3; // metres
  const φ1 = lat1 * Math.PI/180;
  const φ2 = lat2 * Math.PI/180;
  const Δφ = (lat2-lat1) * Math.PI/180;
  const Δλ = (lon2-lon1) * Math.PI/180;

  const a = Math.sin(Δφ/2) * Math.sin(Δφ/2) +
          Math.cos(φ1) * Math.cos(φ2) *
          Math.sin(Δλ/2) * Math.sin(Δλ/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));

  return R * c;
};

export const useAttendance = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const getGPSLocation = (): Promise<GeolocationPosition> => {
    return new Promise((resolve, reject) => {
      if (!navigator.geolocation) {
        reject(new Error("Geolocation is not supported by your browser"));
      }
      navigator.geolocation.getCurrentPosition(resolve, reject, {
        enableHighAccuracy: true,
        timeout: 5000,
        maximumAge: 0
      });
    });
  };

  const checkIfLate = (checkInTime: Date): boolean => {
    const [hours, minutes] = LATE_THRESHOLD_TIME.split(':').map(Number);
    const threshold = new Date(checkInTime);
    threshold.setHours(hours, minutes, 0, 0);
    return checkInTime > threshold;
  };

  const submitCheckIn = async (method: CheckMethod, manualReason?: string) => {
    setLoading(true);
    setError(null);
    try {
      const pos = await getGPSLocation();
      const distance = getDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        OFFICE_COORDS.lat,
        OFFICE_COORDS.lng
      );

      if (distance > MAX_DISTANCE_METERS) {
        throw new Error(`Location verification failed. You are too far from the office (${Math.round(distance)}m).`);
      }

      const now = new Date();
      const isLate = checkIfLate(now);

      const payload = {
        check_in_time: now.toISOString(),
        check_in_method: method,
        location_gps: { lat: pos.coords.latitude, lng: pos.coords.longitude },
        is_late: isLate,
        manual_reason: manualReason,
        status: method === 'qr_scan' ? 'approved' : 'pending'
      };

      // Mock DB call
      console.log("Submitting Check-in:", payload);

      // In real app: const { data, error } = await supabase.from('attendance_records').insert(payload);
      return payload;
    } catch (err: any) {
      setError(err.message || "Failed to check in");
      throw err;
    } finally {
      setLoading(false);
    }
  };

  return { submitCheckIn, loading, error };
};

