                           <span className="text-[10px] text-emerald-600 font-black uppercase bg-emerald-50 px-2 py-1 rounded-full">Approved</span>
                         )}
                      </td>
                      <td className="px-6 py-4">
                        <button className="text-slate-300 hover:text-indigo-600 transition-colors">
                          <i className="fas fa-ellipsis-v"></i>
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

