                {logs.filter(l => {
                  const u = employees.find(e => e.id === l.user_id);
                  return u?.full_name.toLowerCase().includes(filter.toLowerCase()) || u?.department?.toLowerCase().includes(filter.toLowerCase());
                }).map((log) => {
                  const user = employees.find(e => e.id === log.user_id);
                  const needsInApproval = log.status === 'pending';
                  const needsOutApproval = log.check_out_time && log.checkout_status === 'pending';

                  return (
                    <tr key={log.id} className="hover:bg-slate-50/30 transition-all group">
                      <td className="px-8 py-6">
                        <div className="flex items-center gap-4">
                          <div className="w-10 h-10 rounded-2xl bg-slate-100 flex items-center justify-center text-slate-400 font-black text-xs group-hover:bg-white transition-colors">
                            {user?.full_name.substring(0, 2)}
                          </div>
                          <div>
                            <p className="text-sm font-black text-slate-900">{user?.full_name}</p>
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">{user?.department}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-8 py-6">
                        <div className="space-y-1">
                          <div className="flex items-center gap-2">
                            <span className="text-xs font-black text-slate-700">IN {new Date(log.check_in_time).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                            {log.is_late && <span className="text-[8px] bg-rose-50 text-rose-500 px-2 py-0.5 rounded-full font-black uppercase tracking-tight">Late</span>}
                          </div>
                          {log.check_out_time && (
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">
                              OUT {new Date(log.check_out_time).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </p>
                          )}
                        </div>
                      </td>
                      <td className="px-8 py-6">
                        <div className="flex flex-col gap-1.5">
                          <div className="flex items-center gap-2">
                            <span className={`text-[9px] px-2 py-1 rounded-lg font-black uppercase tracking-widest ${log.check_in_method === 'qr_scan' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                              {log.check_in_method.replace('_', ' ')}
                            </span>
                            <span className="text-[9px] text-slate-300"><i className="fas fa-map-marker-alt"></i></span>
                          </div>
                          {log.check_out_method && (
                            <span className={`text-[9px] px-2 py-1 rounded-lg font-black uppercase tracking-widest w-fit ${log.check_out_method === 'qr_scan' ? 'bg-emerald-50 text-emerald-600' : 'bg-sky-50 text-sky-600'}`}>
                              {log.check_out_method.replace('_', ' ')}
                            </span>
                          )}
                        </div>
                      </td>
                      <td className="px-8 py-6">
                         {(needsInApproval || needsOutApproval) ? (
                            <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 space-y-3 max-w-[200px] animate-in pulse">
                               <p className="text-[10px] text-slate-500 font-medium italic line-clamp-2 leading-relaxed">
                                 "{log.manual_reason || log.manual_checkout_reason}"
                               </p>
                               <div className="flex gap-2">
                                  <button 
                                    onClick={() => handleApproval(log.id, needsInApproval ? 'checkin' : 'checkout', 'approve')}
                                    className="flex-1 bg-emerald-600 text-white py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-emerald-700 transition-colors shadow-lg shadow-emerald-100"
                                  >
                                    Accept
                                  </button>
                                  <button 
                                    onClick={() => handleApproval(log.id, needsInApproval ? 'checkin' : 'checkout', 'reject')}
                                    className="flex-1 bg-white border border-slate-200 text-slate-400 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest hover:text-rose-500 transition-colors"
                                  >
                                    Deny
                                  </button>
                               </div>
                            </div>
                         ) : (
                           <div className="flex items-center gap-2">
                              <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
                              <span className="text-[10px] text-emerald-600 font-black uppercase tracking-widest">Verified Log</span>
                           </div>
                         )}
                      </td>
                      <td className="px-8 py-6 text-right">
                        <button className="text-slate-300 hover:text-indigo-600 p-2 rounded-xl transition-all">
                          <i className="fas fa-ellipsis-h text-lg"></i>
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

