import React, { useState, useEffect } from 'react';
import QRScanner from './QRScanner';
import { useAttendance } from '../hooks/useAttendance';
import { COLORS } from '../constants';
import { Notification } from '../types';

const EmployeeView: React.FC = () => {
  const [showScanner, setShowScanner] = useState(false);
  const [showManualForm, setShowManualForm] = useState<'checkin' | 'checkout' | null>(null);
  const [reason, setReason] = useState("");
  const { submitCheckIn, submitCheckOut, loading, error, isOnline } = useAttendance();
  const [checkedIn, setCheckedIn] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);

  // Mock Notifications
  const [notifications, setNotifications] = useState<Notification[]>([
    { id: '1', user_id: 'u1', title: 'Check-in Approved', message: 'Your manual check-in for yesterday has been approved by HR.', is_read: false, type: 'success', created_at: new Date().toISOString() },
    { id: '2', user_id: 'u1', title: 'Late Arrival', message: 'You checked in after 08:30 AM today.', is_read: true, type: 'warning', created_at: new Date().toISOString() }
  ]);

  const handleQRScan = async (data: string) => {
    setShowScanner(false);
    try {
      if (!checkedIn) {
        await submitCheckIn('qr_scan');
        setCheckedIn(true);
      } else {
        await submitCheckOut('qr_scan');
        setCheckedIn(false);
      }
      alert("Scan success! Record updated.");
    } catch (err) {}
  };

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const trimmedReason = reason.trim();
    if (trimmedReason.length < 20) {
      alert("Please provide a more detailed reason (at least 20 characters).");
      return;
    }

    try {
      if (showManualForm === 'checkin') {
        await submitCheckIn('manual', trimmedReason);
        alert("Manual check-in request sent for HR approval.");
        // We stay in 'checked out' state visually until approval in a real app, 
        // but for this demo, we'll assume the request is pending.
      } else {
        await submitCheckOut('manual', trimmedReason);
        alert("Manual check-out request sent for HR approval. Your session is now pending finalization.");
        setCheckedIn(false); // Visually end the session for the employee
      }
      setShowManualForm(null);
      setReason("");
    } catch (err) {
      // Error is handled via the hook's error state
    }
  };

  const unreadCount = notifications.filter(n => !n.is_read).length;

  return (
    <div className="space-y-6 max-w-md mx-auto px-1">
      {/* Network Status & Notifications */}
      <div className="flex justify-between items-center py-2">
        <div className="flex items-center gap-2">
          <div className={`w-2.5 h-2.5 rounded-full ${isOnline ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]' : 'bg-rose-500'} animate-pulse`}></div>
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
            {isOnline ? 'Bujumbura Server Connected' : 'Offline Mode'}
          </span>
        </div>
        <button 
          onClick={() => setShowNotifications(!showNotifications)}
          className="relative p-2.5 bg-white border border-slate-100 rounded-xl shadow-sm hover:text-indigo-600 transition-all"
        >
          <i className="fas fa-bell text-lg"></i>
          {unreadCount > 0 && (
            <span className="absolute -top-1 -right-1 bg-rose-500 text-white text-[9px] w-5 h-5 flex items-center justify-center rounded-full border-2 border-white font-black">
              {unreadCount}
            </span>
          )}
        </button>
      </div>

      {/* Notification Panel */}
      {showNotifications && (
        <div className="bg-white border border-slate-100 rounded-3xl shadow-2xl overflow-hidden animate-in fade-in slide-in-from-top-4 z-50 relative">
          <div className="p-5 bg-slate-50/50 border-b border-slate-100 flex justify-between items-center">
            <h4 className="font-black text-slate-800 text-xs uppercase tracking-widest">Messages</h4>
            <button className="text-[10px] text-indigo-600 font-bold uppercase hover:underline" onClick={() => setNotifications(notifications.map(n => ({...n, is_read: true})))}>Clear</button>
          </div>
          <div className="max-h-80 overflow-y-auto">
            {notifications.length === 0 ? (
              <div className="p-10 text-center text-slate-300 text-sm font-medium">No alerts today</div>
            ) : (
              notifications.map(n => (
                <div key={n.id} className={`p-5 border-b border-slate-50 flex gap-4 transition-colors ${n.is_read ? 'bg-white' : 'bg-indigo-50/20'}`}>
                  <div className={`mt-1.5 w-2 h-2 rounded-full shrink-0 ${n.type === 'success' ? 'bg-emerald-500' : n.type === 'warning' ? 'bg-amber-500' : 'bg-indigo-500'}`}></div>
                  <div className="space-y-1">
                    <p className="text-sm font-bold text-slate-900">{n.title}</p>
                    <p className="text-xs text-slate-500 leading-relaxed font-medium">{n.message}</p>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {/* Main Action Area */}
      <div className="bg-white p-6 rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-50 space-y-6">
        <div className="text-center space-y-1">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">Attendance State</p>
          <div className={`text-2xl font-black tracking-tight ${checkedIn ? 'text-emerald-600' : 'text-slate-300'}`}>
            {checkedIn ? 'ACTIVE SESSION' : 'NOT SIGNED IN'}
          </div>
        </div>

        <button 
          onClick={() => setShowScanner(true)}
          className={`w-full ${checkedIn ? 'bg-rose-500 hover:bg-rose-600' : 'bg-indigo-600 hover:bg-indigo-700'} text-white py-6 rounded-3xl font-black text-xl shadow-lg shadow-indigo-200 flex flex-col items-center justify-center gap-2 active:scale-95 transition-all`}
          disabled={loading}
        >
          {loading ? (
            <i className="fas fa-circle-notch animate-spin text-2xl"></i>
          ) : (
            <>
              <i className={`fas ${checkedIn ? 'fa-sign-out-alt' : 'fa-qrcode'} text-3xl`}></i>
              <span className="text-sm uppercase tracking-widest">{checkedIn ? 'Check Out QR' : 'Check In QR'}</span>
            </>
          )}
        </button>

        <div className="grid grid-cols-2 gap-4">
          {!checkedIn ? (
            <button 
              onClick={() => setShowManualForm('checkin')}
              className="bg-slate-50 border border-slate-200 text-slate-600 py-4 rounded-2xl font-bold flex flex-col items-center gap-1 hover:bg-white transition-all text-xs uppercase tracking-wider"
            >
              <i className="fas fa-keyboard text-lg mb-1"></i>
              Manual In
            </button>
          ) : (
            <button 
              onClick={() => setShowManualForm('checkout')}
              className="bg-slate-50 border border-slate-200 text-slate-600 py-4 rounded-2xl font-bold flex flex-col items-center gap-1 hover:bg-white transition-all text-xs uppercase tracking-wider"
            >
              <i className="fas fa-keyboard text-lg mb-1 text-rose-400"></i>
              Manual Out
            </button>
          )}
          <div className="bg-slate-50 border border-slate-200 p-4 rounded-2xl flex flex-col items-center justify-center text-center">
            <p className="text-[9px] font-black text-slate-400 uppercase">Weekly Score</p>
            <p className="text-lg font-black text-slate-800">92%</p>
          </div>
        </div>
      </div>

      {error && (
        <div className="bg-rose-50 text-rose-600 p-5 rounded-3xl border border-rose-100 text-xs font-bold flex gap-4 animate-in slide-in-from-bottom-2">
          <i className="fas fa-shield-alt text-lg"></i>
          <span className="leading-tight">{error}</span>
        </div>
      )}

      {/* Manual Approval Modal */}
      {showManualForm && (
        <div className="fixed inset-0 z-[60] flex items-end sm:items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-md p-8 rounded-[3rem] shadow-2xl space-y-6 animate-in slide-in-from-bottom-10 duration-300">
            <div className="flex justify-between items-start">
              <div className="space-y-1">
                <h3 className="font-black text-slate-900 text-lg uppercase tracking-tight">
                  {showManualForm === 'checkin' ? 'Manual Arrival' : 'Manual Departure'}
                </h3>
                <p className="text-xs text-slate-500 font-medium">Explain why you aren't using the QR code scanner.</p>
              </div>
              <button onClick={() => setShowManualForm(null)} className="p-2 text-slate-300 hover:text-slate-600">
                <i className="fas fa-times text-xl"></i>
              </button>
            </div>

            <form onSubmit={handleManualSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">
                  Reason for {showManualForm === 'checkin' ? 'Check-in' : 'Check-out'} (Min 20 chars)
                </label>
                <textarea
                  className="w-full bg-slate-50 border border-slate-200 rounded-[2rem] p-5 text-sm font-medium focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 focus:outline-none min-h-[140px] resize-none transition-all"
                  placeholder="Example: My camera is malfunctioning and couldn't focus on the office QR today..."
                  value={reason}
                  onChange={(e) => setReason(e.target.value)}
                  required
                ></textarea>
                <div className="flex justify-between px-2">
                   <span className={`text-[10px] font-bold ${reason.trim().length < 20 ? 'text-rose-400' : 'text-emerald-500'}`}>
                     {reason.trim().length}/20 characters
                   </span>
                </div>
              </div>

              <button 
                type="submit"
                className="w-full bg-slate-900 text-white py-5 rounded-[2rem] font-black text-sm uppercase tracking-[0.2em] shadow-xl hover:bg-black transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                disabled={loading || reason.trim().length < 20}
              >
                {loading ? 'Processing...' : `Submit ${showManualForm === 'checkin' ? 'Check-in' : 'Check-out'}`}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Today's Log Card */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
        <h3 className="font-black text-slate-800 text-[10px] uppercase tracking-widest mb-4">Live Session Log</h3>
        <div className="space-y-4">
          {checkedIn ? (
            <div className="flex items-center justify-between p-4 bg-emerald-50/50 rounded-2xl border border-emerald-100">
              <div className="flex items-center gap-4">
                <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center text-white shadow-sm shadow-emerald-200">
                  <i className="fas fa-check text-sm"></i>
                </div>
                <div>
                  <p className="text-xs font-black text-slate-800 uppercase tracking-tighter">Checked In</p>
                  <p className="text-[10px] text-slate-500 font-bold uppercase">08:14 • QR Verified</p>
                </div>
              </div>
              <div className="text-right">
                <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest bg-emerald-100 px-2 py-1 rounded-full">On Time</span>
              </div>
            </div>
          ) : (
            <div className="p-8 text-center space-y-3">
              <div className="w-12 h-12 bg-slate-50 rounded-full mx-auto flex items-center justify-center text-slate-200">
                <i className="fas fa-moon text-xl"></i>
              </div>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">No active session recorded</p>
            </div>
          )}
        </div>
      </div>

      {showScanner && (
        <QRScanner onScan={handleQRScan} onClose={() => setShowScanner(false)} />
      )}
    </div>
  );
};

