                          </div>
                        )}
                        {log.is_late && <p className="text-[10px] text-rose-400 font-bold italic">"Late: {log.late_reason}"</p>}
                      </td>
                      <td className="px-8 py-6">
                        {(inPending || outPending) ? (
                          <div className="space-y-2">
