                              <button onClick={() => handleLogApproval(log.id, inPending ? 'checkin' : 'checkout', 'approved')} className="bg-emerald-500 text-white text-[9px] font-black uppercase px-3 py-1.5 rounded-lg shadow-sm">Accept</button>
