              <button onClick={() => setShowManualForm(null)} className="text-slate-300 hover:text-slate-600"><i className="fas fa-times text-xl"></i></button>
            </div>
            <form onSubmit={handleManualSubmit} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Manual Justification (Min 20 chars)</label>
                <textarea
                  required
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 focus:outline-none min-h-[100px] resize-none"
                  placeholder="Detailed reason for not using QR code..."
                  value={reason}
                  onChange={(e) => setReason(e.target.value)}
                />
              </div>

              {showManualForm === 'checkin' && isCurrentTimeLate && (
                <div className="space-y-1 p-4 bg-amber-50 rounded-2xl border border-amber-100">
                  <label className="text-[10px] font-black text-amber-600 uppercase tracking-widest flex items-center gap-2">
                    <i className="fas fa-clock"></i> Late Arrival Reason
                  </label>
                  <textarea
                    required
                    className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-medium focus:ring-2 focus:ring-amber-500 focus:outline-none min-h-[80px] resize-none mt-2"
                    placeholder="Why are you arriving past 08:30 AM?"
                    value={lateReason}
                    onChange={(e) => setLateReason(e.target.value)}
                  />
                </div>
              )}

              <button 
                type="submit"
                disabled={reason.trim().length < 20 || (showManualForm === 'checkin' && isCurrentTimeLate && lateReason.trim().length < 10)}
                className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase text-sm tracking-widest shadow-lg disabled:opacity-50"
              >
                Request Approval
              </button>
            </form>
          </div>
        </div>
      )}

      {showScanner && <QRScanner onScan={handleQRScan} onClose={() => setShowScanner(false)} />}
    </div>
  );
};

