import React, { useState, useEffect, useMemo } from 'react';
import QRScanner from './QRScanner';
import { useAttendance } from '../hooks/useAttendance';
import { COLORS } from '../constants';
import { Notification } from '../types';

const EmployeeView: React.FC = () => {
  const [showScanner, setShowScanner] = useState(false);
  const [showManualForm, setShowManualForm] = useState<'checkin' | 'checkout' | null>(null);
  const [showLateForm, setShowLateForm] = useState(false);
  const [lateReason, setLateReason] = useState("");
  const [reason, setReason] = useState("");
  const { submitCheckIn, submitCheckOut, loading, error, isOnline, checkIfLate } = useAttendance();
  const [checkedIn, setCheckedIn] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);

  const [notifications, setNotifications] = useState<Notification[]>([
    { id: '1', user_id: 'u1', title: 'Check-in Approved', message: 'Your manual check-in for yesterday has been approved by HR.', is_read: false, type: 'success', created_at: new Date().toISOString() },
    { id: '2', user_id: 'u1', title: 'Late Arrival', message: 'You checked in after 08:30 AM today.', is_read: true, type: 'warning', created_at: new Date().toISOString() },
    { id: '3', user_id: 'u1', title: 'System Update', message: 'Bujumbura HQ office hours updated to 08:00 AM - 05:00 PM.', is_read: false, type: 'info', created_at: new Date().toISOString() }
  ]);

  const isCurrentTimeLate = useMemo(() => checkIfLate(new Date()), []);

  const handleQRScan = async (data: string) => {
    setShowScanner(false);
    const now = new Date();
    const isLate = checkIfLate(now);

    if (!checkedIn && isLate) {
      setShowLateForm(true);
      return;
    }

    try {
      if (!checkedIn) {
        await submitCheckIn('qr_scan');
        setCheckedIn(true);
      } else {
        await submitCheckOut('qr_scan');
        setCheckedIn(false);
      }
      alert("Scan success! Record updated.");
    } catch (err) {}
  };

  const handleLateSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (lateReason.trim().length < 10) {
      alert("Please provide a valid reason for being late (at least 10 chars).");
      return;
    }
    try {
      await submitCheckIn('qr_scan', undefined, lateReason);
      setCheckedIn(true);
      setShowLateForm(false);
      setLateReason("");
      alert("Late check-in recorded.");
    } catch (err) {}
  };

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const trimmedReason = reason.trim();
    if (trimmedReason.length < 20) {
      alert("Please provide a more detailed reason (at least 20 characters).");
      return;
    }

    if (showManualForm === 'checkin' && isCurrentTimeLate && lateReason.trim().length < 10) {
      alert("Please provide a valid reason for being late (at least 10 chars).");
      return;
    }

    try {
      if (showManualForm === 'checkin') {
        await submitCheckIn('manual', trimmedReason, isCurrentTimeLate ? lateReason : undefined);
        alert("Manual check-in request sent for HR approval.");
        setCheckedIn(true); 
      } else {
        await submitCheckOut('manual', trimmedReason);
        alert("Manual check-out request sent for HR approval.");
        setCheckedIn(false);
      }
      setShowManualForm(null);
      setReason("");
      setLateReason("");
    } catch (err) {}
  };

  const toggleNotificationRead = (id: string) => {
    setNotifications(prev => prev.map(n => 
      n.id === id ? { ...n, is_read: !n.is_read } : n
    ));
  };

  const markAllRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, is_read: true })));
  };

  const clearAllNotifications = () => {
    if (confirm("Clear all notifications?")) {
      setNotifications([]);
    }
  };

  const unreadCount = useMemo(() => notifications.filter(n => !n.is_read).length, [notifications]);

  return (
    <div className="space-y-6 max-w-md mx-auto px-1 relative">
      {/* Header Stats */}
      <div className="flex justify-between items-center py-2">
        <div className="flex items-center gap-2">
          <div className={`w-2.5 h-2.5 rounded-full ${isOnline ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]' : 'bg-rose-500'} animate-pulse`}></div>
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
            {isOnline ? 'AKTIVATE Cloud Online' : 'Offline Mode'}
          </span>
        </div>
        <div className="relative">
          <button 
            onClick={() => setShowNotifications(!showNotifications)}
            className={`p-2.5 rounded-xl border transition-all ${showNotifications ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-600 shadow-sm hover:border-indigo-200'}`}
          >
            <i className="fas fa-bell text-lg"></i>
            {unreadCount > 0 && (
              <span className="absolute -top-1 -right-1 bg-rose-500 text-white text-[9px] w-5 h-5 flex items-center justify-center rounded-full border-2 border-white font-black animate-in zoom-in duration-300">
                {unreadCount}
              </span>
            )}
          </button>
        </div>
      </div>

      {/* Notifications Panel Overlay */}
      {showNotifications && (
        <div className="absolute top-16 right-0 left-0 z-[100] bg-white border border-slate-100 rounded-[2rem] shadow-2xl overflow-hidden animate-in fade-in slide-in-from-top-4 duration-300 origin-top-right">
          <div className="p-5 bg-slate-50/50 border-b border-slate-100 flex justify-between items-center">
            <div className="flex items-center gap-2">
              <h4 className="font-black text-slate-800 text-[11px] uppercase tracking-widest">Alerts Center</h4>
              {unreadCount > 0 && (
                <span className="bg-indigo-100 text-indigo-700 text-[9px] px-1.5 py-0.5 rounded-full font-bold">{unreadCount} New</span>
              )}
            </div>
            <div className="flex gap-3">
              <button 
                onClick={markAllRead}
                className="text-[9px] text-indigo-600 font-black uppercase hover:underline transition-all disabled:opacity-30"
                disabled={unreadCount === 0}
              >
                Mark all read
              </button>
              <button 
                onClick={clearAllNotifications}
                className="text-[9px] text-slate-400 font-black uppercase hover:text-rose-500 transition-all"
              >
                Clear
              </button>
            </div>
          </div>
          <div className="max-h-[350px] overflow-y-auto overscroll-contain">
            {notifications.length === 0 ? (
              <div className="p-12 text-center">
                <div className="w-12 h-12 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-3">
                  <i className="fas fa-bell-slash text-slate-300"></i>
                </div>
                <p className="text-slate-400 text-xs font-medium">All caught up!</p>
              </div>
            ) : (
              notifications.map(n => (
                <div 
                  key={n.id} 
                  onClick={() => toggleNotificationRead(n.id)}
                  className={`p-5 border-b border-slate-50 flex gap-4 transition-all cursor-pointer group hover:bg-slate-50/50 active:bg-slate-100 ${n.is_read ? 'opacity-60 bg-white' : 'bg-indigo-50/20'}`}
                >
                  <div className={`mt-1.5 w-2 h-2 rounded-full shrink-0 ${n.type === 'success' ? 'bg-emerald-500' : n.type === 'warning' ? 'bg-amber-500' : 'bg-indigo-500'} ${n.is_read ? 'opacity-30' : 'animate-pulse'}`}></div>
                  <div className="space-y-1 flex-1">
                    <p className={`text-[13px] leading-tight ${n.is_read ? 'font-semibold text-slate-500' : 'font-black text-slate-900'}`}>{n.title}</p>
                    <p className="text-[11px] text-slate-500 leading-relaxed font-medium">{n.message}</p>
                  </div>
                  <div className="ml-auto self-center">
                    <div className={`w-6 h-6 rounded-full border flex items-center justify-center transition-all ${n.is_read ? 'bg-emerald-50 border-emerald-100 text-emerald-500' : 'bg-white border-slate-200 text-slate-200 group-hover:border-indigo-200 group-hover:text-indigo-200'}`}>
                      <i className={`fas fa-check text-[10px] ${n.is_read ? 'scale-100' : 'scale-0'} transition-transform`}></i>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {/* Main Actions Card */}
      <div className="bg-white p-6 rounded-[2.5rem] shadow-xl border border-slate-50 space-y-6">
        <div className="text-center space-y-1">
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">Work Status</p>
          <div className={`text-2xl font-black tracking-tight ${checkedIn ? 'text-emerald-600' : 'text-slate-300'}`}>
            {checkedIn ? 'ON THE CLOCK' : 'OFF DUTY'}
          </div>
        </div>

        <button 
          onClick={() => setShowScanner(true)}
          className={`w-full ${checkedIn ? 'bg-rose-500 hover:bg-rose-600' : 'bg-indigo-600 hover:bg-indigo-700'} text-white py-6 rounded-3xl font-black text-xl shadow-lg flex flex-col items-center justify-center gap-2 active:scale-95 transition-all`}
          disabled={loading}
        >
          {loading ? (
            <i className="fas fa-circle-notch animate-spin text-2xl"></i>
          ) : (
            <>
              <i className={`fas ${checkedIn ? 'fa-sign-out-alt' : 'fa-qrcode'} text-3xl`}></i>
              <span className="text-sm uppercase tracking-widest">{checkedIn ? 'Check Out' : 'Check In'}</span>
            </>
          )}
        </button>

        <div className="grid grid-cols-2 gap-4">
          <button 
            onClick={() => setShowManualForm(checkedIn ? 'checkout' : 'checkin')}
            className="bg-slate-50 border border-slate-200 text-slate-600 py-4 rounded-2xl font-bold flex flex-col items-center gap-1 hover:bg-white hover:border-indigo-100 transition-all text-xs uppercase tracking-wider"
          >
            <i className={`fas fa-keyboard text-lg mb-1 ${checkedIn ? 'text-rose-400' : 'text-indigo-400'}`}></i>
            Manual {checkedIn ? 'Out' : 'In'}
          </button>
          <div className="bg-slate-50 border border-slate-200 p-4 rounded-2xl flex flex-col items-center justify-center text-center">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Efficiency</p>
            <p className="text-lg font-black text-slate-800">92%</p>
          </div>
        </div>
      </div>

      {/* Modals remain the same as previous logic */}
      {showLateForm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-sm p-8 rounded-[2.5rem] shadow-2xl space-y-6">
            <div className="text-center space-y-2">
              <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-2xl mx-auto flex items-center justify-center text-2xl">
                <i className="fas fa-clock"></i>
              </div>
              <h3 className="font-black text-slate-900 text-lg uppercase">Late Arrival</h3>
              <p className="text-xs text-slate-500 font-medium">It's after 08:30 AM. Please provide a reason for the delay.</p>
            </div>
            <form onSubmit={handleLateSubmit} className="space-y-4">
              <textarea
                required
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-rose-500 focus:outline-none min-h-[100px] resize-none"
                placeholder="Reason for being late..."
                value={lateReason}
                onChange={(e) => setLateReason(e.target.value)}
              />
              <button 
                type="submit"
                className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase text-sm tracking-widest shadow-lg"
              >
                Submit & Clock In
              </button>
            </form>
          </div>
        </div>
      )}

      {showManualForm && (
        <div className="fixed inset-0 z-[190] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-sm p-8 rounded-[2.5rem] shadow-2xl space-y-6 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-start">
              <h3 className="font-black text-slate-900 text-lg uppercase">{showManualForm === 'checkin' ? 'Manual Check-In' : 'Manual Check-Out'}</h3>
              <button onClick={() => setShowManualForm(null)} className="text-slate-300 hover:text-slate-600"><i className="fas fa-times text-xl"></i></button>
            </div>
            <form onSubmit={handleManualSubmit} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Manual Justification (Min 20 chars)</label>
                <textarea
                  required
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 focus:outline-none min-h-[100px] resize-none"
                  placeholder="Explain why you aren't using the QR scanner..."
                  value={reason}
                  onChange={(e) => setReason(e.target.value)}
                />
              </div>

              {showManualForm === 'checkin' && isCurrentTimeLate && (
                <div className="space-y-2 p-4 bg-amber-50 rounded-2xl border border-amber-100">
                  <label className="text-[10px] font-black text-amber-600 uppercase tracking-widest flex items-center gap-2">
                    <i className="fas fa-clock"></i> Mandatory Late Arrival Reason
                  </label>
                  <textarea
                    required
                    className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs font-medium focus:ring-2 focus:ring-amber-500 focus:outline-none min-h-[80px] resize-none mt-2"
                    placeholder="Why are you arriving past 08:30 AM?"
                    value={lateReason}
                    onChange={(e) => setLateReason(e.target.value)}
                  />
                </div>
              )}

              <button 
                type="submit"
                disabled={reason.trim().length < 20 || (showManualForm === 'checkin' && isCurrentTimeLate && lateReason.trim().length < 10)}
                className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase text-sm tracking-widest shadow-lg disabled:opacity-50"
              >
                Request Approval
              </button>
            </form>
          </div>
        </div>
      )}

      {showScanner && <QRScanner onScan={handleQRScan} onClose={() => setShowScanner(false)} />}
    </div>
  );
};

export default EmployeeView;

import React, { useState, useEffect } from 'react';
import { User, AttendanceRecord } from '../types';
import { generateWeeklyQR, getNextRotationSchedule } from '../services/qrService';

interface AdminDashboardProps {
  users: User[];
  onApproveUser: (userId: string) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, onApproveUser }) => {
  const [filter, setFilter] = useState("");
  const [currentQR, setCurrentQR] = useState<string | null>(null);
  const [nextRotation, setNextRotation] = useState<Date>(getNextRotationSchedule());

  const [roster, setRoster] = useState<User[]>([]);

  const [logs, setLogs] = useState<AttendanceRecord[]>([
    { id: 'r1', user_id: '1', check_in_time: '2024-05-20T08:15:00Z', check_in_method: 'qr_scan', is_late: false, status: 'approved', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r2', user_id: '2', check_in_time: '2024-05-20T08:45:00Z', check_in_method: 'qr_scan', is_late: true, late_reason: 'Heavy traffic on Boulevard de l\'Uprona', status: 'approved', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r3', user_id: '3', check_in_time: '2024-05-20T08:10:00Z', check_in_method: 'manual', is_late: false, status: 'pending', manual_reason: 'Scanner camera focused blurry', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r4', user_id: 'emp-1', check_in_time: '2024-05-20T08:12:00Z', check_out_time: '2024-05-20T17:05:00Z', check_in_method: 'qr_scan', check_out_method: 'manual', is_late: false, status: 'approved', checkout_status: 'pending', manual_checkout_reason: 'Emergency home repair needed', location_gps: { lat: -3.38, lng: 29.36 } },
  ]);

  const pendingUsers = users.filter(u => !u.is_approved);

  useEffect(() => {
    setRoster(users.filter(u => u.is_approved).slice(0, 3));
  }, [users]);

  const handleCycleQR = () => {
    const expiry = new Date();
    expiry.setDate(expiry.getDate() + 7);
    setCurrentQR(generateWeeklyQR(expiry));
    setNextRotation(getNextRotationSchedule());
    alert("QR rotated.");
  };

  const handleLogApproval = (logId: string, type: 'checkin' | 'checkout', action: 'approved' | 'rejected') => {
    setLogs(prev => prev.map(l => {
      if (l.id === logId) {
        if (type === 'checkin') return { ...l, status: action };
        return { ...l, checkout_status: action };
      }
      return l;
    }));
  };

  const stats = [
    { label: 'Present Now', value: roster.length.toString(), icon: 'fa-user-check', color: 'text-emerald-600' },
    { label: 'Pending Users', value: pendingUsers.length.toString(), icon: 'fa-user-plus', color: 'text-indigo-600' },
    { label: 'Manual Flags', value: logs.filter(l => l.status === 'pending' || l.checkout_status === 'pending').length.toString(), icon: 'fa-flag', color: 'text-rose-600' },
  ];

  const filteredLogs = logs.filter(log => {
    const user = users.find(u => u.id === log.user_id);
    return user?.full_name.toLowerCase().includes(filter.toLowerCase()) || 
           user?.department?.toLowerCase().includes(filter.toLowerCase());
  });

  return (
    <div className="space-y-8 max-w-[1400px] mx-auto py-6 px-4">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end gap-4">
        <div className="space-y-1">
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">HR CONTROL <span className="text-indigo-600">CENTRAL</span></h2>
          <p className="text-slate-500 text-sm font-medium">Bujumbura HQ Office Attendance Overview</p>
        </div>
        <button onClick={handleCycleQR} className="bg-indigo-600 hover:bg-indigo-700 transition-colors text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-3 shadow-lg active:scale-95">
          <i className="fas fa-sync-alt"></i> Rotate Office QR
        </button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 flex items-center gap-6">
            <div className={`p-4 rounded-2xl bg-slate-50 ${stat.color} flex items-center justify-center w-14 h-14`}>
              <i className={`fas ${stat.icon} text-xl`}></i>
            </div>
            <div>
              <span className="block text-3xl font-black text-slate-900 leading-none">{stat.value}</span>
              <span className="block text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">{stat.label}</span>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* User Approval Panel */}
        <div className="lg:col-span-4 bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-sm space-y-6 flex flex-col h-fit">
          <div className="flex items-center justify-between">
            <h3 className="font-black text-slate-900 uppercase text-xs tracking-widest">New Registrations</h3>
            <span className="bg-indigo-50 text-indigo-600 text-[10px] px-2 py-0.5 rounded-full font-black uppercase">{pendingUsers.length}</span>
          </div>
          <div className="space-y-4">
            {pendingUsers.length === 0 ? (
              <div className="text-center py-10">
                <div className="w-12 h-12 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-3">
                  <i className="fas fa-user-check text-slate-200"></i>
                </div>
                <p className="text-slate-400 text-xs font-medium italic">No pending registrations</p>
              </div>
            ) : (
              pendingUsers.map(user => (
                <div key={user.id} className="p-4 bg-slate-50 rounded-2xl space-y-4 border border-slate-100/50">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-indigo-100 text-indigo-600 flex items-center justify-center font-black text-lg shadow-sm">
                      {user.full_name[0]}
