                              <p className="text-[9px] text-rose-700 font-black uppercase tracking-widest">Manual Check-Out</p>
                            </div>
                            <p className="text-[10px] text-slate-600 leading-relaxed font-medium line-clamp-2">"{log.manual_checkout_reason}"</p>
                            <div className="flex gap-2">
                              <button onClick={() => handleLogApproval(log.id, 'checkout', 'approved')} className="flex-1 bg-emerald-500 text-white text-[9px] font-black uppercase py-2 rounded-lg shadow-sm hover:bg-emerald-600 transition-colors">Accept</button>
                              <button onClick={() => handleLogApproval(log.id, 'checkout', 'rejected')} className="flex-1 bg-white border border-slate-200 text-rose-500 text-[9px] font-black uppercase py-2 rounded-lg hover:bg-rose-50 transition-colors">Deny</button>
                            </div>
                          </div>
                        ) : (
                          <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 border border-emerald-100 rounded-xl w-fit">
                            <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full shadow-[0_0_8px_rgba(16,185,129,0.3)]"></div>
                            <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Verified Session</span>
                          </div>
                        )}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          {filteredLogs.length === 0 && (
            <div className="flex-1 flex flex-col items-center justify-center p-20 text-center space-y-3">
              <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-slate-200 text-2xl">
                <i className="fas fa-clipboard-list"></i>
              </div>
              <div className="space-y-1">
                <p className="text-slate-900 font-bold">No results found</p>
                <p className="text-slate-400 text-xs">Try adjusting your search criteria</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

