import { QRCodeData } from '../types';

/**
 * Backend Simulation Secret
 * In production, this would be a Supabase Vault secret.
 */
const SERVER_SECRET = "AKTIVATE_HQ_SECURE_2024_BDI_v5";

/**
 * Mocks the logic that would run in a Supabase Edge Function.
 * Returns a unique, encrypted (HMAC-simulated) QR data string.
 */
export const generateWeeklyQR = (expiryDate: Date): QRCodeData => {
  const now = new Date();
  const rotationId = `ROT_${now.getFullYear()}_W${Math.ceil(now.getDate() / 7)}`;

  const payload = {
    iss: 'AKTIVATE_BDI_AUTH',
    iat: Math.floor(now.getTime() / 1000),
    exp: Math.floor(expiryDate.getTime() / 1000),
    rid: rotationId,
    loc: 'BUJ_HQ_1'
  };

  // Simulate signing logic (JWS style)
  const header = btoa(JSON.stringify({ alg: "HS256", typ: "QR" }));
  const data = btoa(JSON.stringify(payload));

  // Create a signature using our secret
  const signature = btoa(`${data}.${SERVER_SECRET}`).substring(0, 16);
  const qrString = `${header}.${data}.${signature}`;

  const qrData: QRCodeData = {
    id: `qr_${Math.random().toString(36).substr(2, 9)}`,
    qr_data: qrString,
    valid_from: now.toISOString(),
    valid_until: expiryDate.toISOString(),
    is_active: true,
    rotation_id: rotationId,
    checksum: signature
  };

  // Simulate database persistence
  localStorage.setItem('aktivate_active_qr', JSON.stringify(qrData));

  return qrData;
};

/**
 * Validates a scanned QR string against the current active record.
 */
export const validateQRCode = (qrString: string): boolean => {
  try {
    const saved = localStorage.getItem('aktivate_active_qr');
    if (!saved) return false;

    const activeQR: QRCodeData = JSON.parse(saved);

    // 1. Structural check
    if (qrString !== activeQR.qr_data) return false;

    // 2. Expiration check
    const now = new Date();
    if (now > new Date(activeQR.valid_until)) return false;

    // 3. Signature validation simulation
    const parts = qrString.split('.');
    const signature = parts[2];
    const data = parts[1];
    const expectedSignature = btoa(`${data}.${SERVER_SECRET}`).substring(0, 16);

    return signature === expectedSignature;
  } catch (e) {
    return false;
  }
};

/**
 * Calculates the next Monday 00:00 UTC for Cron scheduling.
 */
export const getNextRotationSchedule = (): Date => {
  const d = new Date();
  const day = d.getDay();
  const diff = d.getDate() + (day === 0 ? 1 : 8 - day); // Next Monday
  const nextMonday = new Date(d.setDate(diff));
  nextMonday.setHours(0, 0, 0, 0);
  return nextMonday;
};

/**
 * Retrieves the currently active QR record from the "DB".
 */
export const getActiveQR = (): QRCodeData | null => {
  const saved = localStorage.getItem('aktivate_active_qr');
  return saved ? JSON.parse(saved) : null;
};

