// Follows Supabase Edge Function standards (Deno)
import { serve } from "https://deno.land/std@0.168.0/http/server.ts"

const CORS_HEADERS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

/**
 * generate_weekly_qr Edge Function
 * This function is designed to be triggered by pg_cron or manual HR action.
 */
serve(async (req) => {
  // Handle CORS preflight
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: CORS_HEADERS })
  }

  try {
    const { expiry_date } = await req.json()

    // In production, this secret is managed via 'supabase secrets set QR_SYSTEM_SECRET=...'
    const secret = Deno.env.get('QR_SYSTEM_SECRET') || "AKTIVATE_PROD_INTERNAL_SECRET_2024";

    const now = new Date();
    const exp = new Date(expiry_date);

    // Generate a human-readable rotation identifier
    const weekNumber = Math.ceil(now.getDate() / 7);
    const rotationId = `ROT_${now.getFullYear()}_W${weekNumber}_${Math.random().toString(36).substring(7).toUpperCase()}`;

    // Construct the secure payload
    const payloadObj = {
      iss: 'AKTIVATE_AUTH_PROD',
      iat: Math.floor(now.getTime() / 1000),
      exp: Math.floor(exp.getTime() / 1000),
      rid: rotationId,
      loc: 'BUJ_HQ_MAIN'
    };

    const payloadBase64 = btoa(JSON.stringify(payloadObj));

    // Simulate HMAC-SHA256 Signing (In real Deno we use crypto.subtle)
    // We create a robust checksum for the frontend to verify
    const signature = Array.from(
      new Uint8Array(
        await crypto.subtle.digest(
          "SHA-256", 
          new TextEncoder().encode(payloadBase64 + secret)
        )
      )
    ).map(b => b.toString(16).padStart(2, '0')).join('').substring(0, 32);

    const qrData = {
      id: crypto.randomUUID(),
      qr_data: `${payloadBase64}.${signature}`,
      valid_from: now.toISOString(),
      valid_until: exp.toISOString(),
      is_active: true,
      rotation_id: rotationId,
      checksum: signature
    };

    /**
     * Note: In a real implementation, we would use the Supabase Service Role Key 
     * to insert this record into the 'qr_rotations' table here.
     * const supabase = createClient(Deno.env.get('SUPABASE_URL'), Deno.env.get('SUPABASE_SERVICE_ROLE_KEY'))
     * await supabase.from('qr_rotations').insert(qrData)
     */

    return new Response(JSON.stringify(qrData), {
      headers: { ...CORS_HEADERS, 'Content-Type': 'application/json' },
      status: 200,
    });

  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), {
      headers: { ...CORS_HEADERS, 'Content-Type': 'application/json' },
      status: 400,
    });
  }
})

import { QRCodeData } from '../types';

/**
 * This service now simulates the interaction with the Supabase Edge Function.
 * In production, 'generateWeeklyQR' would be a wrapper around a fetch() call to the API.
 */

export const generateWeeklyQR = async (expiryDate: Date): Promise<QRCodeData> => {
  // Simulate network latency for the Edge Function call
  await new Promise(resolve => setTimeout(resolve, 800));

  const now = new Date();
  const weekNumber = Math.ceil(now.getDate() / 7);
  const rotationId = `ROT_${now.getFullYear()}_W${weekNumber}_${Math.random().toString(36).substring(7).toUpperCase()}`;

  // This matches the logic implemented in the Supabase Edge Function
  const payload = {
    iss: 'AKTIVATE_AUTH_PROD',
    iat: Math.floor(now.getTime() / 1000),
    exp: Math.floor(expiryDate.getTime() / 1000),
    rid: rotationId,
    loc: 'BUJ_HQ_MAIN'
  };

  const data = btoa(JSON.stringify(payload));
  // Mocking the server-side HMAC signature
  const signature = btoa(`${data}.PROD_SECRET`).substring(0, 32);
  const qrString = `${data}.${signature}`;

  const qrData: QRCodeData = {
    id: `qr_${Math.random().toString(36).substring(2, 11)}`,
    qr_data: qrString,
    valid_from: now.toISOString(),
    valid_until: expiryDate.toISOString(),
    is_active: true,
    rotation_id: rotationId,
    checksum: signature
  };

  // Persist the "current active" state locally for simulated validation
  localStorage.setItem('aktivate_active_qr', JSON.stringify(qrData));

  return qrData;
};

export const validateQRCode = (qrString: string): boolean => {
  try {
    const saved = localStorage.getItem('aktivate_active_qr');
    if (!saved) return false;

    const activeQR: QRCodeData = JSON.parse(saved);
    if (qrString !== activeQR.qr_data) return false;

    const now = new Date();
    if (now > new Date(activeQR.valid_until)) return false;

    return true;
  } catch (e) {
    return false;
  }
};

export const getNextRotationSchedule = (): Date => {
  const d = new Date();
  const day = d.getDay();
  // Set to next Monday at 00:00:00
  const diff = d.getDate() + (day === 0 ? 1 : 8 - day);
  const nextMonday = new Date(d.setDate(diff));
  nextMonday.setHours(0, 0, 0, 0);
  return nextMonday;
};

export const getActiveQR = (): QRCodeData | null => {
  const saved = localStorage.getItem('aktivate_active_qr');
  return saved ? JSON.parse(saved) : null;
};

