interface AdminDashboardProps {
  users: User[];
  onApproveUser: (userId: string) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, onApproveUser }) => {
  const [filter, setFilter] = useState("");
  const [activeQR, setActiveQR] = useState<QRCodeData | null>(getActiveQR());
  const [rotationLogs, setRotationLogs] = useState<RotationLog[]>([
    { timestamp: new Date().toISOString(), event: 'Initial QR System Boot', status: 'system' }
  ]);

  const [logs, setLogs] = useState<AttendanceRecord[]>([
    { id: 'r1', user_id: 'hr-1', check_in_time: '2024-05-20T08:15:00Z', check_in_method: 'qr_scan', is_late: false, status: 'approved', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r2', user_id: 'emp-1', check_in_time: '2024-05-20T08:45:00Z', check_in_method: 'qr_scan', is_late: true, late_reason: 'Heavy traffic on Boulevard de l\'Uprona', status: 'approved', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r3', user_id: 'emp-1', check_in_time: '2024-05-21T08:10:00Z', check_in_method: 'manual', is_late: false, status: 'pending', manual_reason: 'Scanner camera focused blurry', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r4', user_id: 'emp-1', check_in_time: '2024-05-22T08:12:00Z', check_out_time: '2024-05-22T17:05:00Z', check_in_method: 'qr_scan', check_out_method: 'manual', is_late: false, status: 'approved', checkout_status: 'pending', manual_checkout_reason: 'Emergency home repair needed', location_gps: { lat: -3.38, lng: 29.36 } },
  ]);

  const pendingUsers = users.filter(u => !u.is_approved);

  const handleManualRotation = async () => {
    const nextExp = getNextRotationSchedule();
    const newQR = await generateWeeklyQR(nextExp);
    setActiveQR(newQR);
    setRotationLogs(prev => [
      { timestamp: new Date().toISOString(), event: `Manual Rotation: ${newQR.rotation_id}`, status: 'success' },
      ...prev
    ]);
