          <div className="bg-slate-900 text-white rounded-[2.5rem] p-8 shadow-2xl space-y-6 overflow-hidden relative">
            <div className="absolute -top-10 -right-10 w-40 h-40 bg-indigo-500/10 rounded-full blur-3xl"></div>

            <div className="flex justify-between items-center">
              <h3 className="font-black text-indigo-400 uppercase text-xs tracking-widest">Rotation Console</h3>
              <i className="fas fa-microchip text-indigo-500/50 text-xl"></i>
            </div>

            <div className="space-y-4">
              <div className="p-4 bg-white/5 rounded-2xl border border-white/10">
                <p className="text-[9px] text-indigo-300 font-bold uppercase tracking-widest mb-1">Active Rotation ID</p>
                <p className="text-lg font-black tracking-tight">{activeQR?.rotation_id || 'NOT_INITIALIZED'}</p>
              </div>

              <div className="p-4 bg-white/5 rounded-2xl border border-white/10">
                <p className="text-[9px] text-indigo-300 font-bold uppercase tracking-widest mb-1">Payload Signature</p>
