                  <p className="text-xs font-bold text-white">
                    {activeQR ? new Date(activeQR.valid_until).toLocaleDateString() : '---'}
                  </p>
                </div>
                <button 
                  onClick={handleManualRotation}
                  className="bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all shadow-lg shadow-indigo-500/20 active:scale-95"
                >
                  <i className="fas fa-sync-alt mr-2"></i> Rotate
