                {rotationLogs.map((log, i) => (
                  <div key={i} className="flex gap-2 text-[10px] font-mono">
                    <span className="text-slate-500 shrink-0">[{new Date(log.timestamp).toLocaleTimeString([], { hour12: false })}]</span>
                    <span className={log.status === 'success' ? 'text-emerald-400' : 'text-indigo-400'}>{log.event}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* New Registrations */}
          <div className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-sm space-y-6">
            <div className="flex items-center justify-between">
              <h3 className="font-black text-slate-900 uppercase text-xs tracking-widest">New Registrations</h3>
              <span className="bg-indigo-50 text-indigo-600 text-[10px] px-2 py-0.5 rounded-full font-black uppercase">{pendingUsers.length}</span>
            </div>
            <div className="space-y-4">
              {pendingUsers.length === 0 ? (
                <div className="text-center py-6">
                  <p className="text-slate-400 text-xs font-medium italic">No pending requests</p>
