                              <div className="flex gap-2">
                                <button onClick={() => handleLogApproval(log.id, 'checkout', 'approved')} className="flex-1 bg-emerald-500 text-white text-[9px] font-black uppercase py-2 rounded-lg hover:bg-emerald-600 transition-colors">Accept</button>
                                <button onClick={() => handleLogApproval(log.id, 'checkout', 'rejected')} className="flex-1 bg-white border border-slate-200 text-rose-500 text-[9px] font-black uppercase py-2 rounded-lg hover:bg-rose-50 transition-colors">Deny</button>
                              </div>
                            </div>
                          )}

                          {!isCheckInPending && !isCheckOutPending && (
                            <div className={`flex items-center gap-2 px-3 py-1.5 border rounded-xl w-fit ${log.status === 'approved' && (log.checkout_status === 'approved' || !log.check_out_time) ? 'bg-emerald-50 border-emerald-100' : 'bg-slate-50 border-slate-100'}`}>
                              <div className={`w-1.5 h-1.5 rounded-full ${log.status === 'approved' ? 'bg-emerald-500' : 'bg-rose-500'}`}></div>
                              <span className={`text-[10px] font-black uppercase tracking-widest ${log.status === 'approved' ? 'text-emerald-600' : 'text-slate-500'}`}>
                                {log.status === 'approved' ? 'Verified Session' : 'Rejected'}
                              </span>
                            </div>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: rgba(255,255,255,0.05); }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 10px; }
      `}</style>
    </div>
  );
};

