  const [currentTime, setCurrentTime] = useState(new Date());
  const [activeQR, setActiveQR] = useState<QRCodeData | null>(getActiveQR());
  const [rotationLogs, setRotationLogs] = useState<RotationLog[]>([
    { timestamp: new Date().toISOString(), event: 'Initial QR System Boot', status: 'system' }
  ]);

  // Simulated Realtime State
  const [logs, setLogs] = useState<AttendanceRecord[]>([
    { id: 'r1', user_id: 'hr-1', check_in_time: new Date(new Date().setHours(8, 15)).toISOString(), check_in_method: 'qr_scan', is_late: false, status: 'approved', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r2', user_id: 'emp-1', check_in_time: new Date(new Date().setHours(8, 45)).toISOString(), check_in_method: 'qr_scan', is_late: true, late_reason: 'Heavy traffic on Boulevard de l\'Uprona', status: 'approved', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r3', user_id: 'emp-1', check_in_time: '2024-05-21T08:10:00Z', check_in_method: 'manual', is_late: false, status: 'pending', manual_reason: 'Scanner camera focused blurry', location_gps: { lat: -3.38, lng: 29.36 } },
