  ]);

  // Update clock for "Time at desk" calculations
  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 10000); // Update every 10s
    return () => clearInterval(timer);
  }, []);

  /**
   * SUPABASE REALTIME SUBSCRIPTION MOCKup
