  const [logs, setLogs] = useState<AttendanceRecord[]>([
    { id: 'r1', user_id: 'hr-1', check_in_time: new Date(new Date().setHours(8, 15)).toISOString(), check_in_method: 'qr_scan', is_late: false, status: 'approved', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r2', user_id: 'emp-1', check_in_time: new Date(new Date().setHours(8, 45)).toISOString(), check_in_method: 'qr_scan', is_late: true, late_reason: 'Heavy traffic near Prince Louis Rwagasore Hospital', status: 'approved', location_gps: { lat: -3.38, lng: 29.36 } },
