    { id: 'r4', user_id: 'emp-1', check_in_time: '2024-05-22T08:12:00Z', check_out_time: '2024-05-22T17:05:00Z', check_in_method: 'qr_scan', check_out_method: 'manual', is_late: false, status: 'approved', checkout_status: 'pending', manual_checkout_reason: 'Emergency site visit at client location', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r5', user_id: 'emp-3', check_in_time: '2024-05-21T09:30:00Z', check_in_method: 'manual', is_late: true, status: 'rejected', late_reason: 'Overslept', manual_reason: 'App was not working (False claim)', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r6', user_id: 'emp-2', check_in_time: '2024-05-21T08:05:00Z', check_out_time: '2024-05-21T17:15:00Z', check_in_method: 'qr_scan', check_out_method: 'qr_scan', is_late: false, status: 'approved', location_gps: { lat: -3.38, lng: 29.36 } },
    { id: 'r7', user_id: 'emp-1', check_in_time: '2024-05-20T08:22:00Z', check_out_time: '2024-05-20T18:00:00Z', check_in_method: 'qr_scan', check_out_method: 'qr_scan', is_late: false, status: 'approved', location_gps: { lat: -3.38, lng: 29.36 } },
  ]);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 10000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const timeout = setTimeout(() => {
      const demoCheckIn: AttendanceRecord = {
        id: `realtime-${Date.now()}`,
        user_id: 'emp-2',
        check_in_time: new Date().toISOString(),
        check_in_method: 'qr_scan',
        is_late: false,
        status: 'approved',
        location_gps: { lat: -3.38, lng: 29.36 }
      };

      const alreadyIn = logs.some(l => l.user_id === 'emp-2' && !l.check_out_time && new Date(l.check_in_time).toDateString() === new Date().toDateString());

      if (!alreadyIn) {
        setLogs(prev => [demoCheckIn, ...prev]);
        setRotationLogs(prev => [{ timestamp: new Date().toISOString(), event: 'Real-time Sync: Alice M. checked in', status: 'system' }, ...prev]);
      }
    }, 8000);

    return () => clearTimeout(timeout);
  }, [logs]);

  const pendingUsers = users.filter(u => !u.is_approved);

  const liveRoster = useMemo(() => {
    const today = new Date().toDateString();
    return logs.filter(log => {
      const isToday = new Date(log.check_in_time).toDateString() === today;
      return isToday && !log.check_out_time && log.status === 'approved';
    }).map(log => ({
      ...log,
      user: users.find(u => u.id === log.user_id)
    }));
  }, [logs, users]);

  const handleManualRotation = async () => {
    const nextExp = getNextRotationSchedule();
    const newQR = await generateWeeklyQR(nextExp);
    setActiveQR(newQR);
    setRotationLogs(prev => [
      { timestamp: new Date().toISOString(), event: `Manual Rotation: ${newQR.rotation_id}`, status: 'success' },
      ...prev
