            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Supabase Realtime Active</span>
          </div>
        </div>
      </div>

      {/* Real-time Roster Strip */}
      <section className="bg-indigo-600 rounded-[2.5rem] p-8 shadow-2xl text-white overflow-hidden relative">
         <div className="absolute top-0 right-0 p-8 opacity-10">
           <i className="fas fa-users-viewfinder text-9xl"></i>
         </div>
         <div className="flex items-center gap-4 mb-8">
            <div className="bg-white/20 p-3 rounded-2xl backdrop-blur-md">
              <i className="fas fa-radar text-xl"></i>
            </div>
            <div>
              <h3 className="font-black uppercase text-xs tracking-widest text-indigo-200">Live Roster</h3>
              <p className="text-2xl font-black">Current On-Site Presence</p>
            </div>
            <div className="ml-auto flex items-center gap-2 bg-indigo-500/30 px-4 py-2 rounded-xl border border-white/10">
              <span className="text-2xl font-black">{liveRoster.length}</span>
              <span className="text-[10px] font-black uppercase tracking-widest opacity-70">Staff Active</span>
            </div>
         </div>

         <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
           {liveRoster.length === 0 ? (
             <div className="col-span-full py-12 flex flex-col items-center justify-center opacity-40 border-2 border-dashed border-white/20 rounded-3xl">
                <i className="fas fa-user-slash text-4xl mb-4"></i>
                <p className="font-black uppercase text-[10px] tracking-widest">No active check-ins detected</p>
             </div>
           ) : (
             liveRoster.map((item) => (
               <div key={item.id} className="bg-white/10 backdrop-blur-xl border border-white/10 p-5 rounded-3xl flex items-center gap-4 group hover:bg-white/20 transition-all animate-in zoom-in-95 duration-300">
                  <div className="relative">
                    <div className="w-12 h-12 rounded-2xl bg-white/20 flex items-center justify-center font-black text-lg">
                      {item.user?.full_name[0]}
