import React, { useState, useEffect, useMemo } from 'react';
import { User, AttendanceRecord, QRCodeData, RotationLog } from '../types';
import { generateWeeklyQR, getNextRotationSchedule, getActiveQR } from '../services/qrService';

interface AdminDashboardProps {
  users: User[];
  onApproveUser: (userId: string) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ users, onApproveUser }) => {
  const [filter, setFilter] = useState("");
  const [currentTime, setCurrentTime] = useState(new Date());
  const [activeQR, setActiveQR] = useState<QRCodeData | null>(getActiveQR());
  const [rotationLogs, setRotationLogs] = useState<RotationLog[]>([
    { timestamp: new Date().toISOString(), event: 'Initial QR System Boot', status: 'system' }
  ]);

  // Rich dataset for testing various scenarios
  const [logs, setLogs] = useState<AttendanceRecord[]>([
    { 
      id: 'r1', 
      user_id: 'hr-1', 
      check_in_time: new Date(new Date().setHours(8, 15)).toISOString(), 
      check_out_time: new Date(new Date().setHours(17, 30)).toISOString(),
      check_in_method: 'qr_scan', 
      check_out_method: 'qr_scan',
      is_late: false, 
      status: 'approved', 
      location_gps: { lat: -3.38, lng: 29.36 } 
    },
    { 
      id: 'r2', 
      user_id: 'emp-1', 
      check_in_time: new Date(new Date().setHours(8, 45)).toISOString(), 
      check_in_method: 'qr_scan', 
      is_late: true, 
      late_reason: 'Heavy traffic on Boulevard de l\'Uprona', 
      status: 'approved', 
      location_gps: { lat: -3.38, lng: 29.36 } 
    },
    { 
      id: 'r3', 
      user_id: 'emp-2', 
      check_in_time: new Date(new Date().setHours(8, 10)).toISOString(), 
      check_in_method: 'manual', 
      is_late: false, 
      status: 'pending', 
      manual_reason: 'Camera focus issues', 
      location_gps: { lat: -3.38, lng: 29.36 } 
    },
    { 
      id: 'r4', 
      user_id: 'emp-1', 
      check_in_time: '2024-05-22T08:12:00Z', 
      check_out_time: '2024-05-22T16:05:00Z', 
      check_in_method: 'qr_scan', 
      check_out_method: 'manual', 
      is_late: false, 
      status: 'approved', 
      checkout_status: 'pending', 
      manual_checkout_reason: 'Site visit for client delivery', 
      location_gps: { lat: -3.38, lng: 29.36 } 
    },
    { 
      id: 'r5', 
      user_id: 'emp-3', 
      check_in_time: '2024-05-21T09:30:00Z', 
      check_in_method: 'manual', 
      is_late: true, 
      status: 'rejected', 
      late_reason: 'Overslept', 
      manual_reason: 'Device battery died', 
      location_gps: { lat: -3.38, lng: 29.36 } 
    },
  ]);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 10000);
    return () => clearInterval(timer);
  }, []);

  const pendingUsers = users.filter(u => !u.is_approved);

  const liveRoster = useMemo(() => {
    const today = new Date().toDateString();
    return logs.filter(log => {
      const isToday = new Date(log.check_in_time).toDateString() === today;
      return isToday && !log.check_out_time && log.status === 'approved';
    }).map(log => ({
      ...log,
      user: users.find(u => u.id === log.user_id)
    }));
  }, [logs, users]);

  const handleManualRotation = async () => {
    const nextExp = getNextRotationSchedule();
    const newQR = await generateWeeklyQR(nextExp);
    setActiveQR(newQR);
    setRotationLogs(prev => [
      { timestamp: new Date().toISOString(), event: `Manual Rotation: ${newQR.rotation_id}`, status: 'success' },
      ...prev
    ]);
  };

  const handleLogApproval = (logId: string, type: 'checkin' | 'checkout', action: 'approved' | 'rejected') => {
    setLogs(prev => prev.map(l => {
      if (l.id === logId) {
        if (type === 'checkin') return { ...l, status: action };
        return { ...l, checkout_status: action };
      }
      return l;
    }));
  };

  const filteredLogs = useMemo(() => {
    return logs.filter(log => {
      const user = users.find(u => u.id === log.user_id);
      return user?.full_name.toLowerCase().includes(filter.toLowerCase()) || 
             user?.department?.toLowerCase().includes(filter.toLowerCase());
    });
  }, [logs, filter, users]);

  const calculateShiftDuration = (start: string, end: string) => {
    const startTime = new Date(start).getTime();
    const endTime = new Date(end).getTime();
    const diff = endTime - startTime;
    const hours = Math.floor(diff / 3600000);
    const minutes = Math.floor((diff % 3600000) / 60000);
    return `${hours}h ${minutes}m`;
  };

  const handleExportCSV = () => {
    const headers = ["Employee Name", "Department", "Check-In Time", "Check-In Method", "Is Late", "Late Reason", "Check-Out Time", "Check-Out Method", "Status"];
    const rows = filteredLogs.map(log => {
      const user = users.find(u => u.id === log.user_id);
      return [
        `"${user?.full_name || 'N/A'}"`,
        `"${user?.department || 'N/A'}"`,
        log.check_in_time,
        log.check_in_method,
        log.is_late ? "YES" : "NO",
        `"${log.late_reason || ''}"`,
        log.check_out_time || "---",
        log.check_out_method || "---",
        log.status
      ];
    });

    const csvContent = [headers.join(","), ...rows.map(r => r.join(","))].join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `aktivate_attendance_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-8 max-w-[1400px] mx-auto py-6 px-4">
      {/* Header Section */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end gap-4">
        <div className="space-y-1">
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">HR CONTROL <span className="text-indigo-600">CENTRAL</span></h2>
          <p className="text-slate-500 text-sm font-medium">Enterprise Access & Verification Infrastructure</p>
        </div>
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-3 bg-white px-4 py-2.5 rounded-2xl border border-slate-100 shadow-sm">
            <div className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-pulse"></div>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Supabase Realtime Active</span>
          </div>
        </div>
      </div>

      {/* Real-time Roster Strip */}
      <section className="bg-indigo-600 rounded-[2.5rem] p-8 shadow-2xl text-white overflow-hidden relative">
         <div className="absolute top-0 right-0 p-8 opacity-10">
           <i className="fas fa-users-viewfinder text-9xl"></i>
         </div>
         <div className="flex items-center gap-4 mb-8">
            <div className="bg-white/20 p-3 rounded-2xl backdrop-blur-md">
              <i className="fas fa-radar text-xl"></i>
            </div>
            <div>
              <h3 className="font-black uppercase text-xs tracking-widest text-indigo-200">Live Roster</h3>
              <p className="text-2xl font-black">Current On-Site Presence</p>
            </div>
            <div className="ml-auto flex items-center gap-2 bg-indigo-500/30 px-4 py-2 rounded-xl border border-white/10">
              <span className="text-2xl font-black">{liveRoster.length}</span>
              <span className="text-[10px] font-black uppercase tracking-widest opacity-70">Staff Active</span>
            </div>
         </div>

         <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
           {liveRoster.length === 0 ? (
             <div className="col-span-full py-12 flex flex-col items-center justify-center opacity-40 border-2 border-dashed border-white/20 rounded-3xl">
                <i className="fas fa-user-slash text-4xl mb-4"></i>
                <p className="font-black uppercase text-[10px] tracking-widest">No active check-ins detected</p>
             </div>
           ) : (
             liveRoster.map((item) => (
               <div key={item.id} className="bg-white/10 backdrop-blur-xl border border-white/10 p-5 rounded-3xl flex items-center gap-4 group hover:bg-white/20 transition-all animate-in zoom-in-95 duration-300">
                  <div className="relative">
                    <div className="w-12 h-12 rounded-2xl bg-white/20 flex items-center justify-center font-black text-lg">
                      {item.user?.full_name[0]}
                    </div>
                    <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-emerald-500 border-2 border-indigo-600 rounded-full"></div>
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-black text-sm truncate">{item.user?.full_name}</p>
                    <div className="flex items-center gap-2 opacity-60">
                      <i className="fas fa-clock text-[8px]"></i>
                      <span className="text-[10px] font-black uppercase tracking-widest">At desk: {calculateShiftDuration(item.check_in_time, new Date().toISOString())}</span>
                    </div>
                  </div>
               </div>
             ))
           )}
         </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Management Sidebar */}
        <div className="lg:col-span-4 space-y-8">
          <div className="bg-slate-900 text-white rounded-[2.5rem] p-8 shadow-2xl space-y-6 overflow-hidden relative">
