                              <span className={`text-[8px] px-2 py-0.5 rounded-full font-black uppercase ${log.check_in_method === 'qr_scan' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-indigo-50 text-indigo-600 border border-indigo-100'}`}>
                                {log.check_in_method.replace('_', ' ')}
                              </span>
                            </div>
                            {log.is_late && (
