                                <button onClick={() => handleLogApproval(log.id, 'checkout', 'rejected')} className="flex-1 bg-white border border-slate-200 text-rose-500 text-[10px] font-black uppercase py-2.5 rounded-xl hover:bg-rose-50 transition-colors">Deny</button>
